var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"대단하군. 그 몸으로 서 있을 수 있다니.","JPN":"素晴らしいな。その体でまだ立っていられるとは。","ENG":"Impressive. You're still standing in that state.","TWN":"真了不起，你居然還能站著。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"정말…… 불사라도 된다는 건가?","JPN":"本当に……不死の身だというのか？","ENG":"Could it be... that you're truly immortal?","TWN":"真的……變成不死之身了嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"경이로울 정도야.","JPN":"実に驚異的だ。","ENG":"Fascinating... truly fascinating.","TWN":"真是令人驚訝。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽…….","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 총알들…… 엄청 비싸겠어…….","JPN":"この弾……すっごく高そう……","ENG":"These bullets... must cost a fortune...","TWN":"這些子彈……一定很貴吧……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"가져다가 팔면…… 진짜 많이 받을 수 있겠……지?","JPN":"持ち帰って売ったら……大儲けできる……かな？","ENG":"If I could sell them... I'd make a killing... right?","TWN":"拿去賣的話……應該能賣很多錢吧……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"마음대로 하게.","JPN":"好きにするといい。","ENG":"Do as you please.","TWN":"隨你便。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"어차피 자네는 밖으로 나갈 수 없을 테니.","JPN":"どうせ君は外には出られないからな。","ENG":"Not that you'll be leaving here anyway.","TWN":"反正你也出不去。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"눈이 뚫려서 보이지 않겠지만, 이곳은 저택 중심부라네.","JPN":"眼球を貫かれて見えていないだろうが、ここは邸宅の中心部さ。","ENG":"You can't see it with your eyes gone, but we're at the heart of my estate.","TWN":"雖然看不見，但這裡是屋子的中心。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"사냥감을 몰듯이 아주 은밀하고, 천천히 자네를 이곳으로 인도했지.","JPN":"獲物を追い込むように、密かに、ゆっくりと君をここへ誘導したのだよ。","ENG":"I've been herding you here, little by little, like a proper hunt.","TWN":"就像驅趕獵物一樣，我非常小心且緩慢地把你引導到這裡。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 상황에서도 입을 나불대지 않으면 죽는 병이라도 걸렸냐?","JPN":"あのさ、さっきからうるさいんだよ。口を閉じてないと死ぬ病気にでもかかってるわけ？","ENG":"Do you have a sickness where you'll die if you stop talking?","TWN":"你是不是得了不說話就會死的病？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"실험이 성공하는 순간은 언제나 들떠서 말이야.","JPN":"実験が成功する瞬間は何度経験しても嬉しいものでね。","ENG":"Ah, but the moment a successful experiment is within reach, it's simply exhilarating.","TWN":"實驗成功的瞬間總是讓人興奮不已。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네도 그렇지 않나?","JPN":"君もそうだろう？","ENG":"Surely, you can relate?","TWN":"你不也是這樣嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"돈을 많이 만진다던가…….","JPN":"大金を手にした時とか……","ENG":"Like when you come into a lot of money...","TWN":"賺了很多錢之類的……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"억지로 공감하는 척하지 마. 역겨우니까.","JPN":"わかったような口を聞かないで。吐き気がするから。","ENG":"Don't act like we have anything in common. It's disgusting.","TWN":"別假裝有共鳴，真讓人噁心。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이런, 난 자네의 모든 것이 궁금한 것뿐이네.","JPN":"おや、私は君のすべてが知りたいだけさ。","ENG":"My, my. I'm just... curious about everything related to you.","TWN":"哎呀，我只是對你的一切都很好奇而已。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"골밀도는 어떻게 변했는지, 자네의 진정한 모습은 어떠한지.","JPN":"骨密度はどう変化したか、君の真の姿はどんなものなのか。","ENG":"How has your bone density changed? What does your true form look like?","TWN":"骨密度發生了怎樣的變化，你的真面目又是怎樣的。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"워치는 붉은 달이 떴을 때 나타난 건가? 식사는 주로 무엇으로 해결하나?","JPN":"ウォッチは赤い月が昇った時現れたのかね？　食事は主に何を食べている？","ENG":"Did you get your watch when the Red Moon appeared? What do you eat?","TWN":"你是在紅月升起時出現的嗎？通常吃什麼？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아까 같은 광증은 처음이었나? 물을 무서워하진 않나?","JPN":"先程のような狂症は始めてだったかな？　水は怖くないのかね？","ENG":"Was that episode of madness a first? Do you fear water?","TWN":"剛才那樣的狂症是第一次嗎？不怕水嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"평소에는 어떤…….","JPN":"普段はどんな……","ENG":"And normally–","TWN":"平時是怎樣的……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"젠장! 나도 말 좀 하자!","JPN":"くそ！　うるさいから黙ってろ！","ENG":"Damn it! Let me get a word in!","TWN":"該死！也讓我說句話！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"침식 쐐기나 부술 줄 알았는데, 이런 변태랑 만날 줄은…….","JPN":"侵食楔を壊すだけで済むと思ったのに、こんな変態と遭遇することになるなんて……","ENG":"I thought I was here to break a Corrupted Wedge, not deal with some freak...","TWN":"我以為會遇到侵蝕釘之類的，沒想到會碰上這種變態……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"빠져나갈 길은 없네.","JPN":"抜け出す方法はない。","ENG":"There's no way out.","TWN":"你不可能逃走的。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네가 날뛸 수 있는 모든 변수를 차단했어.","JPN":"君が脱出できるすべての可能性を遮断してある。","ENG":"I've eliminated every possible variable that could let you fight back.","TWN":"我已經封鎖了你所有可能作亂的變數。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"없긴 뭐가 없어. 이 자식아.","JPN":"ふん、私の退魔履歴をなめないことね。","ENG":"You know nothing, huh?","TWN":"怎麼會沒有，你這傢伙。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아무리 골치 아픈 심령 현상이라도 딱 하나 바뀌지 않는 게 있어.","JPN":"どんなに厄介な心霊現象だろうと、絶対変わらないものが一つある。","ENG":"No matter how tricky the haunting, one thing never changes.","TWN":"無論多麼令人頭痛的靈異現象，有一樣東西是不會改變的。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"바로 침식 쐐기지.","JPN":"それは……侵食楔。","ENG":"The Corrupted Wedge.","TWN":"那就是侵蝕釘。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저 자식만 없으면 넌 어떻게든 쓰러뜨릴 수 있어.","JPN":"あいつさえ潰せば、あなたはなんとか倒せる。","ENG":"If I take that thing out, I can deal with you.","TWN":"只要沒有那傢伙，我就能想辦法打倒你。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어보미네이션을 침식 쐐기로 쓰고 있는 거잖아?","JPN":"アボミネーションを侵食楔として使ってるんでしょう？","ENG":"You're using an Abomination as a Corrupted Wedge, aren't you?","TWN":"你在用憎惡作為侵蝕釘嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저걸 제거한다면, 어느정도 승산이 생기겠지.","JPN":"あれを排除すれば、少しは勝ち目が見えてくるはず。","ENG":"If I get rid of it, my odds improve.","TWN":"如果能除掉那個，勝算就會增加一些。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"날카롭군.","JPN":"鋭いな。","ENG":"Good observation.","TWN":"說的不錯。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"내가 하는 일이 그런 거니까.","JPN":"それが普段、私の仕事だから。","ENG":"It's my job.","TWN":"因為這是我做的事。"},"stage":{"bg":"CITY_CENTER3","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"악령 퇴치를 빙자한 침식 쐐기 부수기.","JPN":"悪霊退治に見せかけた侵食楔壊し。","ENG":"Corrupted Wedge removal disguised as exorcisms.","TWN":"以驅除惡靈為名破壞侵蝕釘。"},"stage":{"bg":"CITY_CENTER3","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"식솔을 실험체로 썼건, 사람을 납치했건 말건, 그건 내 상관할 바가 아니지만.","JPN":"家の人を実験体にしたとか、人を攫ったとかそういうのは私の知ったことじゃないけど。","ENG":"Whatever you did, experimenting on your staff or kidnapping people, that's none of my business.","TWN":"不管是把家人當作實驗品，還是綁架了人，這些都不關我的事。"},"stage":{"bg":"CITY_CENTER3","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈을 떼먹는 것도 모자라 나까지 실험체로 쓰려고 해?","JPN":"代金を踏み倒しておいて、私を実験体にするって？","ENG":"But trying to stiff me on my pay and using me as a lab rat?","TWN":"不僅欠錢不還，還想拿我當實驗品？"},"stage":{"bg":"CITY_CENTER3","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"넌 꼭 내가 끝장 낸다.","JPN":"あなたは絶対この手で始末してやる。","ENG":"I won't let that slide. You're going down.","TWN":"我一定會親手了結你。"},"stage":{"bg":"CITY_CENTER3","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};